import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.mercury.com/docs/getting-started";
const PLACEHOLDER_VALUE =
  "vm0placeholderMercuryToken0000000000000000000000000000a";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Mercury API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:mercury",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const mercuryFirewall: FirewallConfig = {",
    '  name: "mercury",',
    '  description: "Mercury API",',
    "  placeholders: {",
    `    MERCURY_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.mercury.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.MERCURY_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [",
    "        {",
    '          name: "unrestricted",',
    '          description: "Allow all Mercury API endpoints",',
    '          rules: ["ANY /{path*}"],',
    "        },",
    "      ],",
    "    },",
    "  ],",
    "};",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Mercury firewall config...");
  const ts = generateTypeScript();
  writeOutput("mercury", ts, import.meta.dirname);
}
